import React, { useState } from 'react';
import { MenuAlt1Icon, HomeIcon, UserIcon, LogoutIcon } from 'lucide-react';
import { Link } from 'react-router-dom';

const Sidebar = () => {
  const [isOpen, setIsOpen] = useState(true);

  const toggleMenu = () => {
    setIsOpen(!isOpen);
  };

  return (
    <div className="flex h-screen w-64 bg-gray-800 text-gray-400">
      <div className="flex flex-col h-screen">
        <div className="flex items-center justify-between px-6 py-4 border-b border-gray-700 md:px-8 lg:px-10 xl:px-12">
          <Link to="#" className="flex items-center space-x-2">
            <img src="#" alt="Luxuria Logo" className="w-8 h-8" />
            <span className="text-lg font-bold">Luxuria</span>
          </Link>
          <button
            type="button"
            className="rounded-lg p-2 text-gray-200 hover:bg-gray-600"
            onClick={toggleMenu}
          >
            <MenuAlt1Icon className="w-6 h-6" />
          </button>
        </div>

        <div className={`flex-1 ${isOpen ? 'max-h-screen' : 'max-h-0'}`}>
          <div className="flex flex-col space-y-6 px-6 py-4 md:px-8 lg:px-10 xl:px-12">
            <Link to="#" className="flex items-center space-x-2">
              <HomeIcon className="w-6 h-6" />
              <span className="text-sm font-bold">Home</span>
            </Link>
            <Link to="#" className="flex items-center space-x-2">
              <UserIcon className="w-6 h-6" />
              <span className="text-sm font-bold">My Account</span>
            </Link>
            <Link to="#" className="flex items-center space-x-2">
              <LogoutIcon className="w-6 h-6" />
              <span className="text-sm font-bold">Logout</span>
            </Link>
          </div>
        </div>
      </div>
    </div>
  );
};

export default Sidebar;

