import React from 'react';
import { Check } from 'lucide-react';

const PricingPlan = () => {
  const plans = [
    {
      name: 'Standard',
      price: '$49',
      features: [
        'Access to standard rooms',
        'Daily breakfast',
        'Free Wi-Fi',
        '24/7 Concierge',
      ],
      isPopular: false,
    },
    {
      name: 'Deluxe',
      price: '$99',
      features: [
        'Access to deluxe suites',
        'Gourmet breakfast',
        'High-speed Wi-Fi',
        '24/7 Concierge',
        'Spa access',
        'Room service',
      ],
      isPopular: true,
    },
    {
      name: 'Penthouse',
      price: '$199',
      features: [
        'Exclusive penthouse suites',
        'Personalized chef breakfast',
        'Premium high-speed Wi-Fi',
        'Dedicated butler service',
        'Full spa and wellness access',
        'Private dining options',
        'Limousine service',
      ],
      isPopular: false,
    },
  ];

  return (
    <section className="py-20 bg-gray-900 text-gray-300 font-inter">
      <div className="container mx-auto px-4">
        <div className="text-center mb-16">
          <h2 className="text-4xl font-bold text-white mb-4">
            Choose Your Perfect Stay
          </h2>
          <p className="text-xl text-gray-400">
            Luxuria offers unparalleled experiences for every traveler.
          </p>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
          {plans.map((plan, index) => (
            <div
              key={index}
              className={`relative flex flex-col p-8 rounded-2xl shadow-soft-double border border-gray-800 bg-gray-900 transition-all duration-300 ease-in-out
                ${plan.isPopular ? 'scale-105 border-emerald-500' : ''}
                ${plan.isPopular ? 'border-2' : ''}
              `}
            >
              {plan.isPopular && (
                <span className="absolute top-0 right-0 bg-emerald-500 text-white text-xs font-semibold px-3 py-1 rounded-bl-xl rounded-tr-2xl">
                  Most Popular
                </span>
              )}
              <h3 className={`text-3xl font-bold mb-4 ${plan.isPopular ? 'text-emerald-400' : 'text-white'}`}>
                {plan.name}
              </h3>
              <div className="mb-6">
                <span className="text-5xl font-extrabold text-white">{plan.price}</span>
                <span className="text-xl text-gray-400">/night</span>
              </div>
              <ul className="space-y-4 mb-8 flex-grow">
                {plan.features.map((feature, fIndex) => (
                  <li key={fIndex} className="flex items-center">
                    <Check className={`w-6 h-6 mr-3 ${plan.isPopular ? 'text-emerald-400' : 'text-emerald-500'}`} />
                    <span>{feature}</span>
                  </li>
                ))}
              </ul>
              <button
                className={`w-full py-3 px-6 rounded-xl font-bold text-lg transition-all duration-300 ease-in-out
                  ${plan.isPopular ? 'bg-emerald-600 hover:bg-emerald-700 text-white' : 'bg-gray-700 hover:bg-gray-600 text-white'}
                `}
              >
                Choose Plan
              </button>
            </div>
          ))}
        </div>
      </div>
    </section>
  );
};

export default PricingPlan;

